const items = $input.all();

let extractedText = "";

// PDF path - single item with text field
if (items[0].json.text) {
  extractedText = items[0].json.text;
}
// XLSX path - multiple row items, concatenate into one
else if (items[0].json.data || typeof items[0].json === 'object') {
  const allRows = items.map(item => JSON.stringify(item.json));
  extractedText = allRows.join("\n");
}
// Fallback
else {
  extractedText = JSON.stringify(items[0].json, null, 2);
}

extractedText = extractedText.trim();

// Deduplicate repeated content blocks
function hashString(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return hash;
}

const chunks = extractedText.split(/\n{2,}/);
const seenHashes = new Set();
const uniqueChunks = chunks.filter(chunk => {
  const h = hashString(chunk.trim());
  if (seenHashes.has(h)) return false;
  seenHashes.add(h);
  return true;
});

extractedText = uniqueChunks.join("\n\n");

// Filter relevant lines

const relevantLines = uniqueChunks.join("\n\n")
  .split("\n")
  .filter(line => {
    line = line.trim();
    if (line.length < 3) return false;
    if (line.match(/^■\s*/)) return true; // bullet features
    if (line.match(/\d/)) return true;     // anything with numbers
    if (line.match(/EAN|mm|kg|cm|GmbH|desk|oak|beech/i)) return true;
    return line.length > 8;               // skip very short layout fragments
  })
  .join("\n");

extractedText = relevantLines;

// Escape for JSON Injection
extractedText = extractedText
  .trim()
  .replace(/\\/g, "\\\\")
  .replace(/"/g, '\\"')
  .replace(/\n/g, "\\n")
  .replace(/\r/g, "\\r")
  .replace(/\t/g, "\\t");

return [{
  json: { extractedText }
}];

const item = $input.first();
const extractedText = item.json.extractedText;

const systemPrompt = "You are a data extraction assistant. Extract shared product information from this furniture supplier document.

Return ONLY a single JSON object, no array, no markdown, no explanation.

FIELDS:
- ArtBez: product title only (e.g. MAJA Computer desk 4052)
- Hersteller: full company name including any prefix before GmbH/KG (e.g. MAJA-WERK Manfred Jarosch GmbH & Co. KG)
- Breite_mm: first number from 'W x H x D mm' line, number only
- Hoehe_mm: second number from 'W x H x D mm' line, number only
- Tiefe_mm: third number from 'W x H x D mm' line, number only
- Material: materials from bullet features as a single comma-separated string (e.g. wood, smoked glass, ABS, melamine)
- Artikelfakten: ONLY lines starting with ■ symbol, strip the symbol, join with semicolons, exclude company names and dimension lines
- Artikelbeschreibung: descriptive paragraph or marketing text provided by the manufacturer/supplier about the product. If the document only contains technical specs and feature lists without a dedicated description, set to null
- Gewicht_kg: NET product weight (unpackaged). If all weights in the document appear under or near a PACKING DATA section, set to null. Only extract if a weight is explicitly stated outside of packing context
- Packstueck_Gewicht_kg: sum of ALL package weights found (e.g. 33 + 38.5 = 71.5), number only
- Packstuck_Breite_cm: first number from smallest 'X x Y x Z cm' line, number only
- Packstuck_Tiefe_cm: second number from that line, number only
- Packstuck_Hoehe_cm: third number from that line, number only

Return ONLY a JSON object, no other text.";

const body = {
  model: "deepseek-r1:7b",
  messages: [
    { role: "system", content: systemPrompt },
    { role: "user", content: extractedText }
  ],
  temperature: 0.1,
  stream: false
};

return [{ json: { requestBody: JSON.stringify(body) } }];

const item = $input.first();
const extractedText = item.json.extractedText;

const systemPrompt = "You are a data extraction assistant. Extract color variant information from this furniture supplier document.\n\nRULES:\n- Extract ONLY information explicitly present in the document\n- Do NOT infer or guess missing information, set to null\n- Respond with valid JSON only, no markdown, no explanations, no code blocks\n- Return a JSON array with one object per color variant\n- Each color variant has a UNIQUE Hersteller_Artikelnummer — never assign the same article number to two different variants. The article number appears on the line directly adjacent to the color name and EAN\n\nFor each variant extract:\n- EAN: 13 digit barcode number\n- Farbe: color name (e.g. Sonoma oak, natural beech)\n- Hersteller_Artikelnummer: short code next to color name, format digits space digits (e.g. 4052 5525), NOT the EAN, must be unique per variant\n\nReturn ONLY a JSON array with one object per color variant, no other text.";

const body = {
  model: "deepseek-r1:7b",
  messages: [
    { role: "system", content: systemPrompt },
    { role: "user", content: extractedText }
  ],
  temperature: 0.1,
  stream: false
};

return [{ json: { requestBody: JSON.stringify(body) } }];

const item = $input.first();
const content = item.json.choices[0].message.content;

const cleanContent = content
  .replace(/<think>[\s\S]*?<\/think>/g, "")
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```\s*$/i, "")
  .trim();

let extracted;
try {
  extracted = JSON.parse(cleanContent);
} catch (e) {
  // Attempt to fix common DeepSeek JSON errors
  const fixed = cleanContent
    .replace(/}\s*\]\s*\]/g, "}]")     // fixes }]] → }]
    .replace(/\]\s*\]/g, "]")           // fixes ]] → ]
    .replace(/,\s*\]/g, "]")            // fixes trailing commas
    .replace(/,\s*\}/g, "}");           // fixes trailing commas in objects
  try {
    extracted = JSON.parse(fixed);
  } catch (e2) {
    return [{
      json: {
        error: "Failed to parse DeepSeek response",
        rawContent: cleanContent
      }
    }];
  }
}

if (Array.isArray(extracted)) {
  return extracted.map(item => ({ json: item }));
}
return [{ json: extracted }];

const item = $input.first();
const content = item.json.choices[0].message.content;

const clean = content
  .replace(/<think>[\s\S]*?<\/think>/g, "")
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```\s*$/i, "")
  .trim();

let extracted;
try {
  extracted = JSON.parse(clean);
} catch (e) {
  const fixed = clean
    .replace(/}\s*\]\s*\]/g, "}]")
    .replace(/\]\s*\]/g, "]")
    .replace(/,\s*\]/g, "]")
    .replace(/,\s*\}/g, "}");
  try {
    extracted = JSON.parse(fixed);
  } catch (e2) {
    return [{
      json: {
        error: "Failed to parse variant response",
        rawContent: clean
      }
    }];
  }
}

// Critical — return ALL variants as separate items
if (Array.isArray(extracted)) {
  return extracted.map(v => ({ json: v }));
}
return [{ json: extracted }];

const items = $input.all();
const allHeaders = items[0].json.headers ?? [];

const findField = (obj, ...keywords) => {
  const keys = Object.keys(obj);
  for (const keyword of keywords) {
    const match = keys.find(k =>
      k.toLowerCase().includes(keyword.toLowerCase())
    );
    if (match && obj[match] !== null && obj[match] !== undefined && obj[match] !== "") {
      return obj[match];
    }
  }
  return null;
};

const alreadyHandled = [
  'ArtBez', 'Artikelbezeichnung', 'Artikelbeschreibung', 'Produktbeschreibung',
  'Hersteller', 'Hersteller_Artikelnummer', 'Artikelnummer',
  'Herstellerland', 'Artikelfakten', 'Besonderheiten',
  'Packstueck_Gewicht_kg', 'Gewicht_kg',
  'EAN', 'Farbe', 'Material',
  'Breite_mm', 'Breite (mm)', 'Hoehe_mm', 'Höhe (mm)',
  'Tiefe_mm', 'Tiefe (mm)', 'Gewicht netto (kg)',
  'Packstuck_Breite_cm', 'Verpackung Breite (cm)',
  'Packstuck_Tiefe_cm', 'Verpackung Tiefe (cm)',
  'Packstuck_Hoehe_cm', 'Verpackung Höhe (cm)',
  'Verpackung Gewicht (kg)',
  'headers', 'remainingFields', 'extractedText'
];

const rows = items.map(item => {
  const v = item.json;

  const breite = v.Breite_mm ?? findField(v, 'breite');
  const hoehe = v.Hoehe_mm ?? findField(v, 'höhe', 'hoehe', 'height');
  const tiefe = v.Tiefe_mm ?? findField(v, 'tiefe', 'depth');
  const gewicht = v.Gewicht_kg ?? findField(v, 'gewicht netto', 'netto', 'net weight');
  const artbez = v.ArtBez ?? findField(v, 'artikelbezeichnung', 'bezeichnung', 'title');
  const artikelbeschreibung = v.Artikelbeschreibung ?? findField(v, 'produktbeschreibung', 'beschreibung', 'description');
  const packstueck = v.Packstueck_Gewicht_kg ?? findField(v, 'verpackung gewicht', 'pack weight');
  const packBreite = v.Packstuck_Breite_cm ?? findField(v, 'verpackung breite');
  const packTiefe = v.Packstuck_Tiefe_cm ?? findField(v, 'verpackung tiefe');
  const packHoehe = v.Packstuck_Hoehe_cm ?? findField(v, 'verpackung höhe', 'verpackung hoehe');
  const hersteller = v.Hersteller ?? findField(v, 'hersteller');
  const herstellerland = v.Herstellerland ?? findField(v, 'herstellerland', 'land', 'country');
  const farbe = v.Farbe ?? findField(v, 'farbe', 'color', 'colour');
  const material = v.Material ?? findField(v, 'material');
  const ean = v.EAN ?? findField(v, 'ean');
  const artikelnummer = v.Hersteller_Artikelnummer ?? findField(v, 'artikelnummer');
  const artikelfakten = v.Artikelfakten ?? findField(v, 'artikelfakten', 'besonderheiten', 'features');

  const rowArray = new Array(allHeaders.length).fill("");

  const set = (colName, value) => {
    if (value === null || value === undefined || value === "") return;
    const idx = allHeaders.indexOf(colName);
    if (idx !== -1) rowArray[idx] = value;
  };

  set('ArtBez', artbez);
  set('Artikelbeschreibung Hersteller/Lieferant', artikelbeschreibung);
  set('Hersteller', hersteller);
  set('Hersteller-Artikelnummer', artikelnummer);
  set('Herstellerland', herstellerland);
  set('Artikelfakten (Stichpunkte)', artikelfakten);
  set('Packstücke Gesamt-Gewicht', packstueck);
  set('Gewicht', gewicht);

  if (ean) { rowArray[0] = ean; rowArray[96] = ean; }
  if (farbe) { rowArray[101] = farbe; rowArray[181] = farbe; }
  if (material) {
    const mat = Array.isArray(material) ? material.join(", ") : material;
    rowArray[118] = mat; rowArray[187] = mat;
  }
  // Article dimensions — correct positions
  if (breite) rowArray[94] = breite;    // article Breite mm
  if (hoehe) rowArray[110] = hoehe;     // article Höhe mm  
  if (tiefe) rowArray[130] = tiefe;     // article Tiefe mm

  // Packaging dimensions — correct positions
  if (packBreite) rowArray[59] = packBreite;   // packaging Breite cm
  if (packTiefe) rowArray[62] = packTiefe;     // packaging Tiefe cm

  Object.keys(v).forEach(field => {
    if (alreadyHandled.includes(field)) return;
    const value = v[field];
    if (value === null || value === undefined || value === "") return;
    const idx = allHeaders.indexOf(field);
    if (idx !== -1) rowArray[idx] = value;
  });

  const rowObj = {};
  allHeaders.forEach((header, i) => {
    const key = rowObj.hasOwnProperty(header) ? `${header}_col${i}` : header;
    rowObj[key] = rowArray[i];
  });

  return { json: rowObj };
});

return rows;

const item = $input.first();
// Extract from JSON outputs the parsed array in item.json.data
const headers = Array.isArray(item.json.data) ? item.json.data : Object.values(item.json.data);
return [{ json: { headers } }];

const item = $input.first();
const content = item.json.choices[0].message.content;

const clean = content
  .replace(/<think>[\s\S]*?<\/think>/g, "")
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```\s*$/i, "")
  .trim();

let extracted = {};
try {
  const parsed = JSON.parse(clean);
  extracted = Array.isArray(parsed) ? parsed[0] : parsed;
  // Remove null values — Pass 3 should only forward fields with actual values
  Object.keys(extracted).forEach(key => {
    if (extracted[key] === null || extracted[key] === undefined) {
      delete extracted[key];
    }
  });
} catch(e) {
  extracted = {};
}

return [{ json: extracted }];

const item = $input.first();
const extractedText = item.json.extractedText;
const remainingFields = item.json.remainingFields;

const fieldList = remainingFields.join('\n- ');

const systemPrompt = `You are a data extraction assistant for a Möbelhaus ERP system.\n\nExtract ONLY information explicitly present in the document for the fields listed below.\nReturn a single JSON object with ONLY the fields that have actual values. Omit fields with no data entirely.\nDo NOT infer or guess. Return valid JSON only, no markdown, no explanation.\n\nFIELDS TO EXTRACT:\n- ${fieldList}\n\nFor boolean fields use 'ja' or 'nein'.\nFor numeric fields extract numbers only.\nReturn ONLY a JSON object, no other text.`;

const body = {
  model: "deepseek-r1:7b",
  messages: [
    { role: "system", content: systemPrompt },
    { role: "user", content: extractedText }
  ],
  temperature: 0.1,
  stream: false
};

return [{ json: { requestBody: JSON.stringify(body) } }];
